def seed_system_roles(apps, schema_editor):
    """Seed system RoleTemplate rows from the canonical SYSTEM_ROLES definition."""
    from core.utils.rbac_defaults import SYSTEM_ROLES

    RoleTemplate = apps.get_model("core", "RoleTemplate")
    for slug, spec in SYSTEM_ROLES.items():
        RoleTemplate.objects.update_or_create(
            slug=slug,
            defaults={
                "name": spec["name"],
                "description": spec["description"],
                "capability_flags_json": spec["capability_flags_json"],
                "is_system": True,
            },
        )


